const leads = $input.all();
const enrichedLeads = [];

// Helper: Extract domain from email
function extractDomain(email) {
  if (!email) return null;
  const match = email.match(/@([a-zA-Z0-9.-]+\.[a-zA-Z]{2,})$/);
  return match ? match[1].toLowerCase() : null;
}

// Helper: Extract domain from website
function extractDomainFromWebsite(website) {
  if (!website) return null;
  try {
    const url = new URL(website.startsWith('http') ? website : 'https://' + website);
    return url.hostname.replace(/^www\./, '').toLowerCase();
  } catch {
    return null;
  }
}

// Helper: Detect country from phone
function detectGeoFromPhone(phone) {
  if (!phone) return { country: 'Unknown', timezone: 'UTC', code: 'XX' };

  const geoMap = {
    '+1': { country: 'United States', timezone: 'America/New_York', code: 'US' },
    '+44': { country: 'United Kingdom', timezone: 'Europe/London', code: 'GB' },
    '+92': { country: 'Pakistan', timezone: 'Asia/Karachi', code: 'PK' },
    '+91': { country: 'India', timezone: 'Asia/Kolkata', code: 'IN' }
  };

  for (const [prefix, data] of Object.entries(geoMap)) {
    if (phone.startsWith(prefix)) return data;
  }

  return { country: 'Unknown', timezone: 'UTC', code: 'XX' };
}

// Process each lead
for (const item of leads) {
  const lead = item.json;

  const emailDomain = extractDomain(lead.email);
  const websiteDomain = extractDomainFromWebsite(lead.website);
  const primaryDomain = websiteDomain || emailDomain;
  const phoneGeo = detectGeoFromPhone(lead.phone);

  enrichedLeads.push({
    lead_id: lead.id,
    user_id: lead.user_id,
    company_name: lead.company_name,
    domain: primaryDomain,
    detected_country: phoneGeo.country,
    detected_timezone: phoneGeo.timezone,
    phone_country_code: phoneGeo.code,
    website: lead.website,
    has_website: lead.website ? true : false,
    enrichment_stage: 1
  });
}

return enrichedLeads;

